//! WASM indexer runtime using wasmtime.
//!
//! Dual-engine design matching metashrew-runtime:
//! - **Sync engine**: for `run_block()` (called from rayon threads)
//! - **Async engine**: for `call_view()` with fuel-based cooperative yielding

use crate::storage::IndexerStorage;
use prost::Message;
use std::collections::HashMap;
use std::sync::Arc;
use wasmtime::*;

/// Protobuf message for KeyValueFlush (generated by prost).
mod proto {
    include!(concat!(env!("OUT_DIR"), "/metashrew.rs"));
}

/// Host state threaded through the wasmtime `Store`.
pub struct WasmState {
    pub input_data: Vec<u8>,
    pub pending_flush: Option<Vec<(Vec<u8>, Vec<u8>)>>,
    pub storage: Arc<IndexerStorage>,
    pub had_failure: bool,
    pub completed: bool,
    pub label: String,
    pub view_mode: bool,
    pub limits: StoreLimits,
    /// Write-through cache: __flush writes are staged here so subsequent
    /// __get/__get_len calls within the same _start() can read them back.
    /// Matches qubitcoin-indexer-web's write_cache behavior.
    pub write_cache: HashMap<Vec<u8>, Vec<u8>>,
}

/// Build the deterministic engine config matching metashrew-runtime.
fn base_config() -> Config {
    let mut config = Config::new();
    config.wasm_bulk_memory(true);
    config.wasm_multi_value(true);
    config.wasm_reference_types(true);
    config.wasm_simd(true);
    config.cranelift_nan_canonicalization(true);
    config.relaxed_simd_deterministic(true);
    config.memory_reservation(0x100000000); // 4GB
    config.memory_guard_size(0x10000); // 64KB
    // CoW memory init: reuse OS-level copy-on-write pages instead of
    // zeroing memory for each new instance. Eliminates ~12% CPU from
    // page fault handling (clear_page_erms, do_anonymous_page).
    // Must match metashrew-runtime: false ensures deterministic memory
    // initialization. With true, stale memory pages from previous
    // instances can leak, causing non-deterministic WASM execution.
    config.memory_init_cow(true);
    config
}

fn new_state(
    input_data: Vec<u8>,
    storage: Arc<IndexerStorage>,
    label: &str,
    view_mode: bool,
) -> WasmState {
    WasmState {
        input_data,
        pending_flush: None,
        storage,
        had_failure: false,
        completed: false,
        label: label.to_string(),
        view_mode,
        limits: StoreLimitsBuilder::new()
            .memories(usize::MAX)
            .tables(usize::MAX)
            .instances(usize::MAX)
            .build(),
        write_cache: HashMap::new(),
    }
}

/// Ensure WASM memory can grow on demand.
///
/// Unlike metashrew's single-indexer setup which pre-allocates 4GB,
/// we run multiple indexers so we let memory grow on demand via
/// wasmtime's StoreLimits (set to usize::MAX). The static_memory
/// config ensures the address space is reserved without committing
/// physical pages.
fn prepare_memory(_instance: &Instance, _store: &mut Store<WasmState>) {
    // Memory grows on demand via StoreLimits. No pre-allocation needed
    // since memory_reservation(4GB) reserves virtual address space
    // and memory_init_cow(false) ensures deterministic initial state.
}

/// A compiled WASM indexer runtime with dual engines.
pub struct WasmIndexerRuntime {
    /// Sync engine for block processing.
    engine: Engine,
    module: Module,
    /// Async engine with fuel for view functions.
    async_engine: Engine,
    async_module: Module,
}

impl WasmIndexerRuntime {
    /// Compile a WASM module from bytes.
    pub fn new(wasm_bytes: &[u8]) -> Result<Self, String> {
        // Async engine for block processing (matching metashrew/rockshrew).
        // async_support is required because the host functions use
        // func_wrap_async and _start is called with call_async.
        let mut config = base_config();
        config.async_support(true);
        let engine = Engine::new(&config).map_err(|e| format!("wasmtime engine: {}", e))?;
        let module =
            Module::new(&engine, wasm_bytes).map_err(|e| format!("wasmtime compile: {}", e))?;

        // Async engine with fuel for view functions.
        let mut async_config = base_config();
        async_config.async_support(true);
        async_config.consume_fuel(true);
        let async_engine =
            Engine::new(&async_config).map_err(|e| format!("async wasmtime engine: {}", e))?;
        let async_module = Module::new(&async_engine, wasm_bytes)
            .map_err(|e| format!("async wasmtime compile: {}", e))?;

        Ok(WasmIndexerRuntime {
            engine,
            module,
            async_engine,
            async_module,
        })
    }

    /// Run `_start()` for block processing using async execution.
    ///
    /// Uses call_async matching metashrew-runtime's execution model.
    /// This is critical because the alkanes WASM's embedded wasmi interpreter
    /// needs the async fiber stack for deeply recursive extcall operations.
    pub fn run_block(
        &self,
        input_data: Vec<u8>,
        storage: Arc<IndexerStorage>,
        label: &str,
    ) -> Result<Vec<(Vec<u8>, Vec<u8>)>, String> {
        let state = new_state(input_data, storage, label, false);
        let mut store = Store::new(&self.engine, state);
        store.limiter(|s| &mut s.limits);

        // Use async instantiation + execution (matching metashrew).
        let instance = self.instantiate_async_block(&mut store)?;
        prepare_memory(&instance, &mut store);

        let start_fn = instance
            .get_typed_func::<(), ()>(&mut store, "_start")
            .map_err(|e| format!("missing _start: {}", e))?;

        // Use call_async via a one-shot tokio runtime.
        // The async fiber gives the WASM more stack space for
        // deeply nested extcalls.
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .map_err(|e| format!("tokio runtime: {}", e))?;

        rt.block_on(async {
            start_fn
                .call_async(&mut store, ())
                .await
                .map_err(|e| format!("_start failed: {}", e))
        })?;

        let state = store.into_data();
        if state.had_failure {
            return Err("WASM module aborted".into());
        }
        if !state.completed {
            return Err("WASM module did not call __flush".into());
        }

        Ok(state.pending_flush.unwrap_or_default())
    }

    /// Call a view function asynchronously with fuel-based cooperative yielding.
    ///
    /// Uses the async engine so long-running view queries yield back to the
    /// tokio runtime periodically, improving concurrency.
    pub async fn call_view_async(
        &self,
        fn_name: &str,
        input_data: Vec<u8>,
        storage: Arc<IndexerStorage>,
        label: &str,
    ) -> Result<Vec<u8>, String> {
        // Metashrew ABI: view functions also expect [height_le32 ++ payload].
        // Use the current tip height from storage.
        let tip_height = storage.tip_height();
        let mut prefixed_input = Vec::with_capacity(4 + input_data.len());
        prefixed_input.extend_from_slice(&tip_height.to_le_bytes());
        prefixed_input.extend_from_slice(&input_data);
        let state = new_state(prefixed_input, storage, label, true);
        let mut store = Store::new(&self.async_engine, state);
        store.limiter(|s| &mut s.limits);

        // Set fuel for cooperative yielding (matching metashrew).
        store
            .set_fuel(u64::MAX)
            .map_err(|e| format!("set fuel: {}", e))?;
        store
            .fuel_async_yield_interval(Some(10000))
            .map_err(|e| format!("fuel yield interval: {}", e))?;

        let instance = self.instantiate_async(&mut store).await?;
        prepare_memory(&instance, &mut store);

        let view_fn = instance
            .get_typed_func::<(), i32>(&mut store, fn_name)
            .map_err(|e| format!("missing view fn '{}': {}", fn_name, e))?;

        let result_ptr = view_fn
            .call_async(&mut store, ())
            .await
            .map_err(|e| format!("view fn '{}' failed: {}", fn_name, e))?;

        let memory = instance
            .get_memory(&mut store, "memory")
            .ok_or("no memory export")?;

        read_arraybuffer(&store, &memory, result_ptr)
    }

    /// Synchronous view call (for use from non-async contexts like tests).
    pub fn call_view(
        &self,
        fn_name: &str,
        input_data: Vec<u8>,
        storage: Arc<IndexerStorage>,
        label: &str,
    ) -> Result<Vec<u8>, String> {
        // Metashrew ABI: view functions expect [height_le32 ++ payload].
        let tip_height = storage.tip_height();
        let mut prefixed_input = Vec::with_capacity(4 + input_data.len());
        prefixed_input.extend_from_slice(&tip_height.to_le_bytes());
        prefixed_input.extend_from_slice(&input_data);
        let state = new_state(prefixed_input, storage, label, true);
        let mut store = Store::new(&self.engine, state);
        store.limiter(|s| &mut s.limits);

        let instance = self.instantiate_sync(&mut store)?;
        prepare_memory(&instance, &mut store);

        let view_fn = instance
            .get_typed_func::<(), i32>(&mut store, fn_name)
            .map_err(|e| format!("missing view fn '{}': {}", fn_name, e))?;

        let result_ptr = view_fn
            .call(&mut store, ())
            .map_err(|e| format!("view fn '{}' failed: {}", fn_name, e))?;

        let memory = instance
            .get_memory(&mut store, "memory")
            .ok_or("no memory export")?;

        read_arraybuffer(&store, &memory, result_ptr)
    }

    /// Link host functions and instantiate synchronously.
    fn instantiate_sync(&self, store: &mut Store<WasmState>) -> Result<Instance, String> {
        let mut linker = Linker::new(&self.engine);
        link_host_functions_sync(&mut linker)?;
        linker
            .define_unknown_imports_as_traps(&self.module)
            .map_err(|e| format!("define unknown imports: {}", e))?;
        linker
            .instantiate(&mut *store, &self.module)
            .map_err(|e| format!("wasmtime instantiate: {}", e))
    }

    /// Link async host functions and instantiate for block processing.
    /// Uses the same engine (with async_support) as block processing.
    fn instantiate_async_block(&self, store: &mut Store<WasmState>) -> Result<Instance, String> {
        let mut linker = Linker::new(&self.engine);
        link_host_functions_async(&mut linker)?;
        linker
            .define_unknown_imports_as_traps(&self.module)
            .map_err(|e| format!("define unknown imports: {}", e))?;
        // Use blocking instantiate since we're in a sync context
        // (the async comes from call_async on _start)
        let rt = tokio::runtime::Builder::new_current_thread()
            .enable_all()
            .build()
            .map_err(|e| format!("tokio runtime: {}", e))?;
        rt.block_on(async {
            linker
                .instantiate_async(&mut *store, &self.module)
                .await
                .map_err(|e| format!("wasmtime instantiate_async: {}", e))
        })
    }

    /// Link host functions and instantiate asynchronously.
    async fn instantiate_async(
        &self,
        store: &mut Store<WasmState>,
    ) -> Result<Instance, String> {
        let mut linker = Linker::new(&self.async_engine);
        link_host_functions_async(&mut linker)?;
        linker
            .define_unknown_imports_as_traps(&self.async_module)
            .map_err(|e| format!("define unknown imports: {}", e))?;
        linker
            .instantiate_async(&mut *store, &self.async_module)
            .await
            .map_err(|e| format!("wasmtime instantiate_async: {}", e))
    }
}

// ---------------------------------------------------------------------------
// Sync host function linking (for block processing)
// ---------------------------------------------------------------------------

fn link_host_functions_sync(linker: &mut Linker<WasmState>) -> Result<(), String> {
    linker
        .func_wrap("env", "__host_len", |caller: Caller<'_, WasmState>| -> i32 {
            caller.data().input_data.len() as i32
        })
        .map_err(|e| format!("link __host_len: {}", e))?;

    linker
        .func_wrap(
            "env",
            "__load_input",
            |mut caller: Caller<'_, WasmState>, ptr: i32| {
                let data = caller.data().input_data.clone();
                let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
                memory.write(&mut caller, ptr as usize, &data).ok();
            },
        )
        .map_err(|e| format!("link __load_input: {}", e))?;

    linker
        .func_wrap(
            "env",
            "__get_len",
            |mut caller: Caller<'_, WasmState>, key_ptr: i32| -> i32 {
                let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
                let key = match read_arraybuffer(&caller, &memory, key_ptr) {
                    Ok(k) => k,
                    Err(_) => return 0,
                };
                // Check write_cache first (same-block __flush writes)
                if let Some(v) = caller.data().write_cache.get(&key) {
                    return v.len() as i32;
                }
                match caller.data().storage.get_latest(&key)
                    .or_else(|| caller.data().storage.get(&key))
                {
                    Some(v) => v.len() as i32,
                    None => 0,
                }
            },
        )
        .map_err(|e| format!("link __get_len: {}", e))?;

    linker
        .func_wrap(
            "env",
            "__get",
            |mut caller: Caller<'_, WasmState>, key_ptr: i32, value_ptr: i32| {
                let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
                let key = match read_arraybuffer(&caller, &memory, key_ptr) {
                    Ok(k) => k,
                    Err(_) => return,
                };
                // Check write_cache first (same-block __flush writes)
                let value = caller
                    .data()
                    .write_cache
                    .get(&key)
                    .cloned()
                    .or_else(|| {
                        // Use get_latest to resolve the versioned append-only storage
                        caller.data().storage.get_latest(&key)
                            .or_else(|| caller.data().storage.get(&key))
                    });
                if let Some(value) = value {
                    memory.write(&mut caller, value_ptr as usize, &value).ok();
                }
            },
        )
        .map_err(|e| format!("link __get: {}", e))?;

    linker
        .func_wrap(
            "env",
            "__flush",
            |mut caller: Caller<'_, WasmState>, data_ptr: i32| {
                flush_handler(&mut caller, data_ptr);
            },
        )
        .map_err(|e| format!("link __flush: {}", e))?;

    linker
        .func_wrap(
            "env",
            "__log",
            |mut caller: Caller<'_, WasmState>, ptr: i32| {
                log_handler(&mut caller, ptr);
            },
        )
        .map_err(|e| format!("link __log: {}", e))?;

    linker
        .func_wrap(
            "env",
            "abort",
            |mut caller: Caller<'_, WasmState>, msg_ptr: i32, _file: i32, line: i32, col: i32| {
                abort_handler(&mut caller, msg_ptr, line, col);
            },
        )
        .map_err(|e| format!("link abort: {}", e))?;

    Ok(())
}

// ---------------------------------------------------------------------------
// Async host function linking (for view functions with fuel yielding)
// ---------------------------------------------------------------------------

fn link_host_functions_async(linker: &mut Linker<WasmState>) -> Result<(), String> {
    linker
        .func_wrap0_async(
            "env",
            "__host_len",
            |caller: Caller<'_, WasmState>| {
                Box::new(async move { caller.data().input_data.len() as i32 })
            },
        )
        .map_err(|e| format!("link async __host_len: {}", e))?;

    linker
        .func_wrap1_async(
            "env",
            "__load_input",
            |mut caller: Caller<'_, WasmState>, ptr: i32| {
                Box::new(async move {
                    let data = caller.data().input_data.clone();
                    let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
                    memory
                        .write(&mut caller, ptr as usize, &data)
                        .expect("FATAL: __load_input memory write failed");
                })
            },
        )
        .map_err(|e| format!("link async __load_input: {}", e))?;

    linker
        .func_wrap1_async(
            "env",
            "__get_len",
            |mut caller: Caller<'_, WasmState>, key_ptr: i32| {
                Box::new(async move {
                    let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
                    let key = match read_arraybuffer(&caller, &memory, key_ptr) {
                        Ok(k) => k,
                        Err(_) => return 0i32,
                    };
                    if let Some(v) = caller.data().write_cache.get(&key) {
                        return v.len() as i32;
                    }
                    match caller.data().storage.get_latest(&key)
                        .or_else(|| caller.data().storage.get(&key))
                    {
                        Some(v) => v.len() as i32,
                        None => 0,
                    }
                })
            },
        )
        .map_err(|e| format!("link async __get_len: {}", e))?;

    linker
        .func_wrap2_async(
            "env",
            "__get",
            |mut caller: Caller<'_, WasmState>, key_ptr: i32, value_ptr: i32| {
                Box::new(async move {
                    let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
                    let key = match read_arraybuffer(&caller, &memory, key_ptr) {
                        Ok(k) => k,
                        Err(_) => return,
                    };
                    let value = caller
                        .data()
                        .write_cache
                        .get(&key)
                        .cloned()
                        .or_else(|| {
                            caller.data().storage.get_latest(&key)
                                .or_else(|| caller.data().storage.get(&key))
                        });
                    if let Some(value) = value {
                        memory
                            .write(&mut caller, value_ptr as usize, &value)
                            .expect("FATAL: __get memory write failed");
                    }
                })
            },
        )
        .map_err(|e| format!("link async __get: {}", e))?;

    linker
        .func_wrap1_async(
            "env",
            "__flush",
            |mut caller: Caller<'_, WasmState>, data_ptr: i32| {
                Box::new(async move {
                    flush_handler(&mut caller, data_ptr);
                })
            },
        )
        .map_err(|e| format!("link async __flush: {}", e))?;

    linker
        .func_wrap1_async(
            "env",
            "__log",
            |mut caller: Caller<'_, WasmState>, ptr: i32| {
                Box::new(async move {
                    log_handler(&mut caller, ptr);
                })
            },
        )
        .map_err(|e| format!("link async __log: {}", e))?;

    linker
        .func_wrap4_async(
            "env",
            "abort",
            |mut caller: Caller<'_, WasmState>, msg_ptr: i32, _file: i32, line: i32, col: i32| {
                Box::new(async move {
                    abort_handler(&mut caller, msg_ptr, line, col);
                })
            },
        )
        .map_err(|e| format!("link async abort: {}", e))?;

    Ok(())
}

// ---------------------------------------------------------------------------
// Shared host function implementations
// ---------------------------------------------------------------------------

fn flush_handler(caller: &mut Caller<'_, WasmState>, data_ptr: i32) {
    let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
    let data = match read_arraybuffer(&*caller, &memory, data_ptr) {
        Ok(d) => d,
        Err(e) => {
            tracing::error!(error = %e, "failed to read __flush data");
            caller.data_mut().had_failure = true;
            return;
        }
    };

    let flush_msg = match proto::KeyValueFlush::decode(data.as_slice()) {
        Ok(m) => m,
        Err(e) => {
            tracing::error!(error = %e, "failed to decode KeyValueFlush");
            caller.data_mut().had_failure = true;
            return;
        }
    };

    let mut pairs = Vec::new();
    let list = &flush_msg.list;
    let mut i = 0;
    while i + 1 < list.len() {
        pairs.push((list[i].to_vec(), list[i + 1].to_vec()));
        i += 2;
    }

    // Stage flush writes in write_cache so subsequent __get/__get_len
    // calls within the same _start() can read them back. This matches
    // qubitcoin-indexer-web's write_cache behavior.
    for (k, v) in &pairs {
        caller.data_mut().write_cache.insert(k.clone(), v.clone());
    }

    // Do NOT write to RocksDB here — matching qubitcoin-indexer-web which
    // says "storage is not modified (the caller applies pending_flush)".
    // The write_cache handles same-block read-after-write visibility.
    // The caller (run_indexer_block) writes to storage after _start() returns.

    // Accumulate pairs across multiple __flush calls within a single _start().
    match caller.data_mut().pending_flush.as_mut() {
        Some(existing) => existing.extend(pairs),
        None => caller.data_mut().pending_flush = Some(pairs),
    }
    caller.data_mut().completed = true;
}

fn log_handler(caller: &mut Caller<'_, WasmState>, ptr: i32) {
    let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
    if let Ok(msg_bytes) = read_arraybuffer(&*caller, &memory, ptr) {
        let msg = String::from_utf8_lossy(&msg_bytes);
        let label = &caller.data().label;
        tracing::info!(indexer = %label, "{}", msg);
    }
}

fn abort_handler(caller: &mut Caller<'_, WasmState>, msg_ptr: i32, line: i32, col: i32) {
    let memory = caller.get_export("memory").unwrap().into_memory().unwrap();
    let msg = read_arraybuffer(&*caller, &memory, msg_ptr)
        .ok()
        .map(|b| String::from_utf8_lossy(&b).to_string())
        .unwrap_or_else(|| "<unreadable>".into());
    let label = caller.data().label.clone();
    tracing::error!(indexer = %label, line = line, col = col, "WASM abort: {}", msg);
    caller.data_mut().had_failure = true;
}

// ---------------------------------------------------------------------------
// ArrayBuffer helper
// ---------------------------------------------------------------------------

/// Read an AssemblyScript ArrayBuffer from WASM memory.
///
/// Layout: 4-byte LE length at `(ptr - 4)`, then `length` bytes at `ptr`.
fn read_arraybuffer(
    store: impl AsContext,
    memory: &Memory,
    ptr: i32,
) -> Result<Vec<u8>, String> {
    if ptr < 4 {
        return Err("invalid arraybuffer pointer".into());
    }

    let mem_data = memory.data(store.as_context());
    let len_offset = (ptr - 4) as usize;

    if len_offset + 4 > mem_data.len() {
        return Err("arraybuffer length out of bounds".into());
    }

    let len = u32::from_le_bytes([
        mem_data[len_offset],
        mem_data[len_offset + 1],
        mem_data[len_offset + 2],
        mem_data[len_offset + 3],
    ]) as usize;

    let data_offset = ptr as usize;
    if data_offset + len > mem_data.len() {
        return Err("arraybuffer data out of bounds".into());
    }

    Ok(mem_data[data_offset..data_offset + len].to_vec())
}

